package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testWithQuote_withValidCharacter() {
        CSVFormat original = CSVFormat.DEFAULT;
        char quoteChar = '\'';
        CSVFormat result = original.withQuote(quoteChar);
        assertNotNull(result);
        assertEquals(Character.valueOf(quoteChar), result.getQuoteCharacter());
        // Original should remain unchanged
        assertEquals(CSVFormat.DEFAULT.getQuoteCharacter(), original.getQuoteCharacter());
    }

    @Test
    void testWithQuote_withNullCharacter() {
        CSVFormat original = CSVFormat.DEFAULT;
        Character quoteChar = null;
        CSVFormat result = original.withQuote(quoteChar);
        assertNotNull(result);
        assertNull(result.getQuoteCharacter());
    }

    @Test
    void testWithQuote_withLineBreakCharacter_CR() {
        CSVFormat original = CSVFormat.DEFAULT;
        char quoteChar = '\r';
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> {
            original.withQuote(quoteChar);
        });
        assertEquals("The quoteChar cannot be a line break", ex.getMessage());
    }

    @Test
    void testWithQuote_withLineBreakCharacter_LF() {
        CSVFormat original = CSVFormat.DEFAULT;
        char quoteChar = '\n';
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> {
            original.withQuote(quoteChar);
        });
        assertEquals("The quoteChar cannot be a line break", ex.getMessage());
    }

    @Test
    void testWithQuote_withLineBreakCharacter_nullChar() throws Exception {
        // Using reflection to invoke private static isLineBreak(Character)
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        // Test with null character (should return false)
        Boolean result = (Boolean) method.invoke(null, (Character) null);
        assertFalse(result);
    }

    @Test
    void testWithQuote_withLineBreakCharacter_charPrimitive() throws Exception {
        // Using reflection to invoke private static isLineBreak(char)
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        // CR char
        Boolean resultCR = (Boolean) method.invoke(null, (char) '\r');
        assertTrue(resultCR);
        // LF char
        Boolean resultLF = (Boolean) method.invoke(null, (char) '\n');
        assertTrue(resultLF);
        // Non line break char
        Boolean resultA = (Boolean) method.invoke(null, (char) 'A');
        assertFalse(resultA);
    }
}
